import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import {
  LineChart,
  Line,
  BarChart,
  Bar,
  PieChart,
  Pie,
  Cell,
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer
} from "recharts";

const Profile = () => {
  const navigate = useNavigate();
  const userId = localStorage.getItem("userId");
  const token = localStorage.getItem("token");
  const userData = JSON.parse(localStorage.getItem("user") || "{}");

  const [image, setImage] = useState("");
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [bio, setBio] = useState("");
  const [isEditing, setIsEditing] = useState(false);
  const [tempName, setTempName] = useState("");
  const [tempBio, setTempBio] = useState("");
  
  // Chart Data States
  const [profitData, setProfitData] = useState([]);
  const [lossData, setLossData] = useState([]);
  const [expenseData, setExpenseData] = useState([]);
  const [analyticsData, setAnalyticsData] = useState([]);
  const [loadingCharts, setLoadingCharts] = useState(true);
  const [selectedTimeframe, setSelectedTimeframe] = useState("weekly");

  // Colors for charts
  const COLORS = ['#2c3e50', '#e74c3c', '#27ae60', '#f39c12', '#3498db', '#9b59b6'];

  // Redirect if not logged in
  useEffect(() => {
    if (!token) {
      navigate("/login");
    }
  }, [token, navigate]);

  // Load saved profile
  useEffect(() => {
    if (userId && token) {
      const savedData = JSON.parse(localStorage.getItem(`profile_${userId}`)) || {};
      setImage(savedData.image || "");
      setName(savedData.name || userData.name || "");
      setEmail(savedData.email || userData.email || "");
      setBio(savedData.bio || "");
    }
  }, [userId, token, userData]);

  // Load chart data (simulate API call)
  useEffect(() => {
    loadChartData();
  }, [selectedTimeframe]);

  const loadChartData = () => {
    setLoadingCharts(true);
    
    // Simulate API data - In real app, fetch from backend
    setTimeout(() => {
      if (selectedTimeframe === "weekly") {
        setProfitData([
          { day: "Mon", profit: 12000, loss: 3000, expense: 2500 },
          { day: "Tue", profit: 15000, loss: 2000, expense: 2800 },
          { day: "Wed", profit: 18000, loss: 4000, expense: 3200 },
          { day: "Thu", profit: 22000, loss: 3500, expense: 3500 },
          { day: "Fri", profit: 25000, loss: 2800, expense: 3800 },
          { day: "Sat", profit: 28000, loss: 3200, expense: 4200 },
          { day: "Sun", profit: 20000, loss: 2500, expense: 3000 },
        ]);
        
        setLossData([
          { name: "Operational", value: 45 },
          { name: "Marketing", value: 25 },
          { name: "Salaries", value: 20 },
          { name: "Rent", value: 10 },
        ]);
        
        setExpenseData([
          { name: "Inventory", value: 40 },
          { name: "Utilities", value: 15 },
          { name: "Transport", value: 20 },
          { name: "Other", value: 25 },
        ]);
        
        setAnalyticsData([
          { month: "Jan", profit: 85000, loss: 45000 },
          { month: "Feb", profit: 92000, loss: 48000 },
          { month: "Mar", profit: 108000, loss: 52000 },
          { month: "Apr", profit: 115000, loss: 49000 },
          { month: "May", profit: 125000, loss: 53000 },
          { month: "Jun", profit: 142000, loss: 58000 },
        ]);
      } else if (selectedTimeframe === "monthly") {
        setProfitData([
          { day: "Week 1", profit: 55000, loss: 18000, expense: 15000 },
          { day: "Week 2", profit: 68000, loss: 22000, expense: 18000 },
          { day: "Week 3", profit: 72000, loss: 25000, expense: 20000 },
          { day: "Week 4", profit: 89000, loss: 28000, expense: 22000 },
        ]);
        
        setAnalyticsData([
          { month: "Q1", profit: 285000, loss: 145000 },
          { month: "Q2", profit: 382000, loss: 160000 },
          { month: "Q3", profit: 420000, loss: 175000 },
          { month: "Q4", profit: 510000, loss: 190000 },
        ]);
      }
      setLoadingCharts(false);
    }, 500);
  };

  const handleImage = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result);
        const data = { image: reader.result, name, email, bio };
        localStorage.setItem(`profile_${userId}`, JSON.stringify(data));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleEdit = () => {
    setTempName(name);
    setTempBio(bio);
    setIsEditing(true);
  };

  const handleSave = () => {
    setName(tempName);
    setBio(tempBio);
    const data = { image, name: tempName, email, bio: tempBio };
    localStorage.setItem(`profile_${userId}`, JSON.stringify(data));
    setIsEditing(false);
  };

  const handleCancel = () => {
    setIsEditing(false);
  };

  const handleBack = () => {
    navigate(-1);
  };

  const formatCurrency = (amount) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR',
      maximumFractionDigits: 0
    }).format(amount);
  };

  if (!token) {
    return null;
  }

  // Calculate totals
  const totalProfit = profitData.reduce((sum, item) => sum + item.profit, 0);
  const totalLoss = profitData.reduce((sum, item) => sum + (item.loss || 0), 0);
  const totalExpense = profitData.reduce((sum, item) => sum + (item.expense || 0), 0);
  const netProfit = totalProfit - totalLoss - totalExpense;

  return (
    <div style={container}>
      {/* Navigation Bar */}
      <nav style={navbar}>
        <button onClick={handleBack} style={backButton}>
          ← Back to Dashboard
        </button>
        {!isEditing && (
          <button onClick={handleEdit} style={editButton}>
            Edit Profile
          </button>
        )}
      </nav>

      {/* Profile Content */}
      <div style={content}>
        {/* Profile Card */}
        <div style={profileCard}>
          {/* Avatar Section */}
          <div style={avatarSection}>
            <div style={avatarWrapper}>
              <img
                src={image || `https://ui-avatars.com/api/?background=2c3e50&color=fff&bold=true&size=140&name=${(name || "User").charAt(0)}`}
                alt="Profile"
                style={avatar}
              />
              <label style={cameraIcon} htmlFor="profile-image">
                📷
              </label>
              <input
                id="profile-image"
                type="file"
                accept="image/*"
                onChange={handleImage}
                style={{ display: "none" }}
              />
            </div>
          </div>

          {/* Info Section */}
          <div style={infoSection}>
            {isEditing ? (
              <>
                <div style={field}>
                  <label style={label}>Full Name</label>
                  <input
                    type="text"
                    value={tempName}
                    onChange={(e) => setTempName(e.target.value)}
                    style={input}
                    autoFocus
                  />
                </div>
                <div style={field}>
                  <label style={label}>Email</label>
                  <input
                    type="email"
                    value={email}
                    style={{ ...input, background: "#f5f5f5" }}
                    disabled
                  />
                </div>
                <div style={field}>
                  <label style={label}>Bio</label>
                  <textarea
                    value={tempBio}
                    onChange={(e) => setTempBio(e.target.value)}
                    placeholder="Tell us about yourself..."
                    rows="4"
                    style={textarea}
                  />
                </div>
                <div style={actionButtons}>
                  <button onClick={handleSave} style={saveButton}>Save Changes</button>
                  <button onClick={handleCancel} style={cancelButton}>Cancel</button>
                </div>
              </>
            ) : (
              <>
                <h1 style={displayName}>{name || "Set your name"}</h1>
                <p style={displayEmail}>{email}</p>
                <div style={bioBox}>
                  <p style={displayBio}>{bio || "No bio added yet. Click Edit to add one."}</p>
                </div>
              </>
            )}
          </div>
        </div>

        {/* Financial Summary Cards */}
        <div style={statsContainer}>
          <div style={statCard}>
            <div style={statLabel}>Total Profit</div>
            <div style={statValueGreen}>{formatCurrency(totalProfit)}</div>
            <div style={statTrend}>↑ +12.5%</div>
          </div>
          <div style={statCard}>
            <div style={statLabel}>Total Loss</div>
            <div style={statValueRed}>{formatCurrency(totalLoss)}</div>
            <div style={statTrend}>↓ -5.2%</div>
          </div>
          <div style={statCard}>
            <div style={statLabel}>Total Expenses</div>
            <div style={statValueOrange}>{formatCurrency(totalExpense)}</div>
            <div style={statTrend}>↑ +3.8%</div>
          </div>
          <div style={statCard}>
            <div style={statLabel}>Net Profit</div>
            <div style={statValueBlue}>{formatCurrency(netProfit)}</div>
            <div style={statTrend}>↑ +18.3%</div>
          </div>
        </div>

        {/* Timeframe Selector */}
        <div style={timeframeContainer}>
          <button 
            onClick={() => setSelectedTimeframe("weekly")} 
            style={selectedTimeframe === "weekly" ? activeTimeframeBtn : timeframeBtn}
          >
            Weekly
          </button>
          <button 
            onClick={() => setSelectedTimeframe("monthly")} 
            style={selectedTimeframe === "monthly" ? activeTimeframeBtn : timeframeBtn}
          >
            Monthly
          </button>
        </div>

        {loadingCharts ? (
          <div style={loadingContainer}>
            <div style={spinner}></div>
            <p>Loading charts...</p>
          </div>
        ) : (
          <>
            {/* Profit/Loss Line Chart */}
            <div style={chartSection}>
              <h3 style={chartTitle}>Profit & Loss Trend</h3>
              <ResponsiveContainer width="100%" height={300}>
                <LineChart data={profitData}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="day" />
                  <YAxis tickFormatter={(value) => `₹${value/1000}K`} />
                  <Tooltip formatter={(value) => formatCurrency(value)} />
                  <Legend />
                  <Line type="monotone" dataKey="profit" stroke="#27ae60" strokeWidth={2} name="Profit" />
                  <Line type="monotone" dataKey="loss" stroke="#e74c3c" strokeWidth={2} name="Loss" />
                  <Line type="monotone" dataKey="expense" stroke="#f39c12" strokeWidth={2} name="Expense" />
                </LineChart>
              </ResponsiveContainer>
            </div>

            {/* Two Column Charts */}
            <div style={twoColumnGrid}>
              {/* Loss Distribution Pie Chart */}
              <div style={chartSection}>
                <h3 style={chartTitle}>Loss Distribution</h3>
                <ResponsiveContainer width="100%" height={280}>
                  <PieChart>
                    <Pie
                      data={lossData}
                      cx="50%"
                      cy="50%"
                      labelLine={false}
                      label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                      outerRadius={80}
                      fill="#8884d8"
                      dataKey="value"
                    >
                      {lossData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                      ))}
                    </Pie>
                    <Tooltip formatter={(value) => `${value}%`} />
                  </PieChart>
                </ResponsiveContainer>
              </div>

              {/* Expense Distribution Bar Chart */}
              <div style={chartSection}>
                <h3 style={chartTitle}>Expense Distribution</h3>
                <ResponsiveContainer width="100%" height={280}>
                  <BarChart data={expenseData}>
                    <CartesianGrid strokeDasharray="3 3" />
                    <XAxis dataKey="name" />
                    <YAxis />
                    <Tooltip formatter={(value) => `${value}%`} />
                    <Bar dataKey="value" fill="#3498db">
                      {expenseData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                      ))}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>

            {/* Area Chart for Analytics */}
            <div style={chartSection}>
              <h3 style={chartTitle}>Financial Analytics Overview</h3>
              <ResponsiveContainer width="100%" height={300}>
                <AreaChart data={analyticsData}>
                  <CartesianGrid strokeDasharray="3 3" />
                  <XAxis dataKey="month" />
                  <YAxis tickFormatter={(value) => `₹${value/1000}K`} />
                  <Tooltip formatter={(value) => formatCurrency(value)} />
                  <Legend />
                  <Area type="monotone" dataKey="profit" stackId="1" stroke="#27ae60" fill="#27ae60" fillOpacity={0.3} name="Profit" />
                  <Area type="monotone" dataKey="loss" stackId="2" stroke="#e74c3c" fill="#e74c3c" fillOpacity={0.3} name="Loss" />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

